INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e0191851-29e9-45d9-bdec-c1d55cdedf99',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest Testing Pyramid — What to Test at Each Layer$escape$,
  $escape$Jest handles all three layers of the testing pyramid, but mixing responsibilities kills maintainability. Unit tests belong in `.test.ts` files colocated with source — isolate pure functions and hooks using `jest.fn()` and `jest.spyOn()`, mock everything external with `jest.mock('./api')`. They run in milliseconds and should dominate your suite (70%+). Integration tests wire multiple units together without mocking internals — test a Redux slice with its reducer and selectors, or a React component tree using `@testing-library/react` with a real store but a mocked HTTP layer via `jest.mock` or `msw`. These catch contract mismatches between units. E2E belongs in Playwright or Cypress, not Jest — if you're fighting jsdom limitations for a 'full flow' test, that's a signal you've misplaced it. Use `jest.config.ts` projects to enforce separation: define `unit` and `integration` projects with distinct `testMatch` globs and `setupFilesAfterFramework` so each layer gets its own bootstrap. Never let a unit test import from another feature's module without mocking it.$escape$,
  $escape$// jest.config.ts
export default {
  projects: [
    {
      displayName: 'unit',
      testMatch: ['**/*.unit.test.ts'],
      setupFilesAfterFramework: ['<rootDir>/jest.unit.setup.ts'],
    },
    {
      displayName: 'integration',
      testMatch: ['**/*.integration.test.ts'],
      setupFilesAfterFramework: ['<rootDir>/jest.integration.setup.ts'],
    },
  ],
};$escape$,
  $escape$typescript$escape$,
