INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7e82b127-2955-478c-9093-fc870e8eddf2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest — Unit Testing Pure Functions and Custom Hooks with renderHook$escape$,
  $escape$Pure functions are Jest's easiest target: no mocks, no setup — just input/output assertions. Use `test.each` to drive multiple cases without repetition, keeping your suite DRY and exhaustive.

Custom hooks are trickier because they rely on React's runtime. Jest alone can't call a hook directly — you need `renderHook` from `@testing-library/react`. It mounts the hook in a minimal React tree, giving you back `result.current` to inspect state and `act()` to flush updates.

For async hooks (data fetching, debounce), wrap state-changing calls in `act()` — Jest will warn loudly if you forget. Use `waitFor` when the update is asynchronous and you need to poll until an assertion passes.

Pair `renderHook` with `jest.useFakeTimers()` for hooks that use `setTimeout` or `setInterval` — advance time with `jest.advanceTimersByTime(ms)` and assert mid-flight state. Always call `jest.useRealTimers()` in `afterEach` to avoid test bleed.$escape$,
  $escape$import { renderHook, act, waitFor } from '@testing-library/react';
import { useCounter } from './useCounter';

// Pure function
test.each([
  [2, 3, 5],
  [-1, 1, 0],
])('add(%i, %i) === %i', (a, b, expected) => {
  expect(add(a, b)).toBe(expected);
});

// Custom hook
test('useCounter increments', () => {
  const { result } = renderHook(() => useCounter(0));
  act(() => result.current.increment());
  expect(result.current.count).toBe(1);
});$escape$,
