INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '011287d1-4bdf-45da-a09b-cb6b98520f6f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest + Chromatic — Visual Regression Testing for Storybook Stories in CI$escape$,
  $escape$Chromatic wraps Storybook's build output and diffs pixel-by-pixel screenshots across commits — but the test runner that actually executes your stories uses Jest under the hood via `@storybook/test-runner` (built on jest-circus). This means your `play()` functions, `expect()` assertions, and `userEvent` interactions all run through Jest before Chromatic captures the final rendered frame.

Configure `test-runner.ts` at the Storybook root to hook into the Jest lifecycle: use `postVisit` to await animations or fonts before Chromatic snapshots. In CI, run `yarn test-storybook` (Jest) first to catch interaction failures fast and cheap, then run `chromatic --exit-zero-on-changes` to upload the visual build. Gate merges on Chromatic's UI review, not the Jest run — Jest catches broken logic, Chromatic catches broken pixels.

For local diffing without Chromatic, swap in `jest-image-snapshot` via `expect.extend({ toMatchImageSnapshot })` — same Jest `expect` API, but serializes PNG baselines to `__image_snapshots__/`. Delete stale baselines with `--updateSnapshot`, mirroring Jest's snapshot update flow.$escape$,
  $escape$// .storybook/test-runner.ts
import { TestRunnerConfig, waitForPageReady } from '@storybook/test-runner';

const config: TestRunnerConfig = {
  async postVisit(page, context) {
    // Settle animations before Chromatic captures the frame
    await waitForPageReady(page);
    if (context.name.includes('Motion')) {
      await page.waitForTimeout(400);
    }
  },
};

export default config;$escape$,
  $escape$typescript$escape$,
