INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a4e8cfe8-ea6b-42e0-a465-8ab88e55d88b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest + axe-core — Automated Accessibility Checks in Every Test$escape$,
  $escape$jest-axe wraps axe-core and plugs directly into Jest's `expect` API, letting you catch a11y violations as part of your existing test suite — no browser required. Install `jest-axe` and call `toHaveNoViolations()` after rendering with any DOM-producing utility.

The key is `axe()` which accepts a DOM node or HTML string and returns a results object. Pair it with `@testing-library/react`'s `render` for a tight loop: render → query container → run axe → assert. Jest's `expect.extend(toHaveNoViolations)` registers the custom matcher globally — put this in your `setupFilesAfterFramework` so you don't repeat it per file.

axe-core checks 50+ rules by default: missing `alt`, insufficient color contrast, invalid ARIA roles, missing form labels. You can scope rules via the second argument to `axe()` — pass `{ rules: { 'color-contrast': { enabled: false } } }` to skip rules that don't apply or require visual context. Run the full suite in CI; failures surface as readable Jest diff output listing exact WCAG violation codes.$escape$,
  $escape$// setupFilesAfterFramework: jest.setup.ts
import { toHaveNoViolations } from 'jest-axe';
expect.extend(toHaveNoViolations);

// LoginForm.a11y.test.tsx
import { render } from '@testing-library/react';
import { axe } from 'jest-axe';
import { LoginForm } from './LoginForm';

it('has no axe violations', async () => {
  const { container } = render(<LoginForm />);
  const results = await axe(container);
  expect(results).toHaveNoViolations();
});$escape$,
  $escape$typescript$escape$,
