INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'acfc69d3-278d-4600-a175-4f29cb5934c4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest Test Data Management — Factories, Fixtures, and Seeding State Without the Mess$escape$,
  $escape$Hardcoding test objects inline is the fastest way to create brittle tests. Jest has no built-in factory system, but you can build a lightweight one using plain functions with `Object.assign` or spread overrides — no library needed.

A factory function returns a complete, valid object with sensible defaults. Call it with partial overrides per test. Pair this with `beforeEach` to seed fresh state and `afterEach` to tear it down, preventing cross-test contamination that `jest.clearAllMocks()` alone won't catch.

For fixtures — static JSON snapshots of API responses — store them in `__fixtures__/` and import directly. Jest's module resolver handles this without any config. Use `jest.mock()` to swap a real module for a fixture-returning mock at the module boundary, not inside the test body.

When seeding async state (e.g. a Redux store or React Query cache), wrap setup in `beforeEach` with `await` and reset via `queryClient.clear()` or `store.dispatch(resetAction())`. Never share mutable state across `describe` blocks — Jest runs them in the same process and isolation is your responsibility.$escape$,
  $escape$// __tests__/factories/user.factory.ts
export const createUser = (overrides: Partial<User> = {}): User => ({
  id: 'user-1',
  name: 'Alice',
  role: 'viewer',
  createdAt: new Date('2024-01-01'),
  ...overrides,
});

// In your test
beforeEach(() => {
  jest.clearAllMocks();
});

it('restricts access for viewers', () => {
  const user = createUser({ role: 'viewer' });
  expect(canEdit(user)).toBe(false);
});

it('allows edit for admins', () => {
  const user = createUser({ role: 'admin' });
  expect(canEdit(user)).toBe(true);
});$escape$,
