INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a8f9c039-0c10-4781-8017-149a942e059f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest CI Integration — Parallelizing Tests, Caching, and Fail-Fast Strategies$escape$,
  $escape$Jest's `--runInBand` is a CI killer — drop it unless you're debugging. By default, Jest spawns worker processes equal to available CPUs minus one. On CI, explicitly set `--maxWorkers=50%` to avoid memory exhaustion on shared runners, or use `--maxWorkers=4` for predictable parallelism on known hardware.

Enable the transform cache by persisting `jest-cache` between runs. Point Jest at it with `--cacheDirectory=.jest-cache` and cache that directory in your CI config. This skips Babel/SWC transforms on unchanged files — a 40–60% speedup on warm runs.

For fail-fast behavior, `--bail=1` halts the entire suite on the first test failure, saving runner minutes on obviously broken branches. Pair it with `--testPathPattern` to scope runs to changed files using `git diff`.

Shard large suites across parallel CI jobs using `--shard=1/3`, `--shard=2/3`, `--shard=3/3`. Jest splits by file count, not duration — combine with `--testSequencer` pointing to a custom class that orders files by historical runtime for balanced shards.$escape$,
  $escape$# .github/workflows/test.yml (relevant jobs section)
jobs:
  test:
    strategy:
      matrix:
        shard: [1, 2, 3]
    steps:
      - uses: actions/cache@v4
        with:
          path: .jest-cache
          key: jest-${{ hashFiles('**/package-lock.json') }}
      - run: |
          npx jest \
            --shard=${{ matrix.shard }}/3 \
            --maxWorkers=50% \
            --cacheDirectory=.jest-cache \
            --bail=1 \
            --ci$escape$,
  $escape$bash$escape$,
