INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fbb8525e-4e5a-4811-941c-0a9cdf4d63a9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest + Storybook — Reusing Stories as Jest Test Fixtures with composeStories$escape$,
  $escape$Storybook's `composeStories` utility lets Jest consume your `.stories` files directly as pre-configured render fixtures, eliminating the dual-maintenance problem of keeping test setup and story setup in sync. Import `composeStories` from `@storybook/react`, pass in the entire story module, and get back fully decorated components — with args, decorators, and loaders already applied. Render them in Jest via `@testing-library/react` exactly like any other component. This means a `Primary` story with mocked props becomes your Jest test's source of truth. When the story's args change, the Jest test automatically reflects it. For interaction testing, stories with `play` functions can be executed inside Jest using `@storybook/test-runner` or manually invoked via `composeStory` + `userEvent`. This pattern enforces story-first development: if you can't write a story for a component state, you can't test it either. It also makes CI meaningful — `jest` runs actual user-facing component configurations, not synthetic one-off test setups that diverge from what's documented.$escape$,
  $escape$// Button.test.tsx
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { composeStories } from '@storybook/react';
import * as stories from './Button.stories';

const { Primary, Disabled } = composeStories(stories);

test('Primary story fires onClick via jest mock', async () => {
  const onClick = jest.fn();
  render(<Primary onClick={onClick} />);
  await userEvent.click(screen.getByRole('button'));
  expect(onClick).toHaveBeenCalledTimes(1);
});

test('Disabled story does not fire onClick', async () => {
  const onClick = jest.fn();
  render(<Disabled onClick={onClick} />);
  await userEvent.click(screen.getByRole('button'));
  expect(onClick).not.toHaveBeenCalled();
});$escape$,
